import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { quizAPI } from '../../services/api';
import QuizQuestion from './QuizQuestion';
import QuizResults from './QuizResults';
import './Quiz.css';

const Quiz = () => {
  const [questions, setQuestions] = useState([]);
  const [currentQuestion, setCurrentQuestion] = useState(0);
  const [answers, setAnswers] = useState([]);
  const [showResults, setShowResults] = useState(false);
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(true);
  const [quizStarted, setQuizStarted] = useState(false);
  const [error, setError] = useState('');

  const { user } = useAuth();

  useEffect(() => {
    fetchQuestions();
  }, []);

  const fetchQuestions = async () => {
    try {
      setLoading(true);
      setError('');
      const response = await quizAPI.getQuestions();
      if (response.success) {
        setQuestions(response.questions);
      } else {
        setError('Failed to load quiz questions');
      }
    } catch (err) {
      setError('Error loading quiz. Please try again.');
      console.error('Error fetching questions:', err);
    } finally {
      setLoading(false);
    }
  };

  const startQuiz = () => {
    setQuizStarted(true);
    setError('');
  };

  const handleAnswer = (answerIndex) => {
    const newAnswers = [...answers];
    newAnswers[currentQuestion] = answerIndex;
    setAnswers(newAnswers);

    if (currentQuestion < questions.length - 1) {
      setCurrentQuestion(currentQuestion + 1);
    } else {
      submitQuiz(newAnswers);
    }
  };

  const submitQuiz = async (quizAnswers) => {
    setLoading(true);
    setError('');
    try {
      const response = await quizAPI.submitQuiz(quizAnswers);
      if (response.success) {
        setResults(response.results);
        setShowResults(true);
      } else {
        setError('Failed to process quiz results');
      }
    } catch (err) {
      setError('Error submitting quiz. Please try again.');
      console.error('Error submitting quiz:', err);
    } finally {
      setLoading(false);
    }
  };

  const goBack = () => {
    if (currentQuestion > 0) {
      setCurrentQuestion(currentQuestion - 1);
    }
  };

  const retakeQuiz = () => {
    setCurrentQuestion(0);
    setAnswers([]);
    setShowResults(false);
    setResults(null);
    setQuizStarted(false);
    setError('');
  };

  if (!user) {
    return (
      <div className="quiz-container">
        <div className="container">
          <div className="auth-required">
            <h2>Authentication Required</h2>
            <p>Please log in to take the career assessment quiz.</p>
          </div>
        </div>
      </div>
    );
  }

  if (loading && !quizStarted) {
    return (
      <div className="quiz-container">
        <div className="container">
          <div className="loading">
            <div className="spinner"></div>
            Loading quiz questions...
          </div>
        </div>
      </div>
    );
  }

  if (error && !quizStarted) {
    return (
      <div className="quiz-container">
        <div className="container">
          <div className="error-state">
            <h2>Oops! Something went wrong</h2>
            <p>{error}</p>
            <button onClick={fetchQuestions} className="btn btn-primary">
              Try Again
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (showResults && results) {
    return <QuizResults results={results} onRetake={retakeQuiz} />;
  }

  if (!quizStarted) {
    return (
      <div className="quiz-container">
        <div className="container">
          <div className="quiz-intro">
            <h1>Career Assessment Quiz</h1>
            <p className="quiz-description">
              Discover your ideal career path with our intelligent assessment. 
              Answer {questions.length} simple questions about your interests, skills, and preferences.
            </p>
            
            <div className="quiz-info">
              <div className="info-card">
                <h3>What to expect:</h3>
                <ul>
                  <li>⏱️ 5-7 minutes to complete</li>
                  <li>🎯 Personalized career matches</li>
                  <li>📚 Curated learning resources</li>
                  <li>💡 Actionable insights</li>
                  <li>💾 Results saved to your profile</li>
                </ul>
                
                <div className="quiz-stats">
                  <div className="stat">
                    <h4>{questions.length}</h4>
                    <p>Questions</p>
                  </div>
                  <div className="stat">
                    <h4>100%</h4>
                    <p>Free</p>
                  </div>
                  <div className="stat">
                    <h4>Instant</h4>
                    <p>Results</p>
                  </div>
                </div>
                
                <button 
                  onClick={startQuiz} 
                  className="btn btn-primary start-quiz-btn"
                  disabled={questions.length === 0}
                >
                  {questions.length === 0 ? 'Loading...' : 'Start Career Assessment'}
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="quiz-container">
      <div className="quiz-progress">
        <div 
          className="progress-bar" 
          style={{ width: `${((currentQuestion + 1) / questions.length) * 100}%` }}
        ></div>
        <span>Question {currentQuestion + 1} of {questions.length}</span>
      </div>

      {error && (
        <div className="quiz-error">
          <div className="error-message">{error}</div>
          <button onClick={() => setError('')} className="btn btn-secondary">
            Dismiss
          </button>
        </div>
      )}

      {questions.length > 0 && (
        <QuizQuestion
          question={questions[currentQuestion]}
          questionNumber={currentQuestion + 1}
          totalQuestions={questions.length}
          onAnswer={handleAnswer}
          selectedAnswer={answers[currentQuestion]}
          onBack={goBack}
          canGoBack={currentQuestion > 0}
        />
      )}

      {loading && (
        <div className="quiz-loading-overlay">
          <div className="spinner"></div>
          <p>Processing your results...</p>
        </div>
      )}
    </div>
  );
};

export default Quiz;
